下面的.zshrc配置有什么意义# 设置 token
$env:CNB_TOKEN = ""  # your token

function mrm {
    $branch = git rev-parse --abbrev-ref HEAD
    git push origin "${branch}:mr/master/${branch}"
    git cnb pull create -H "mr/master/${branch}" -B master
}

function mrt2 {
    $branch = git rev-parse --abbrev-ref HEAD
    git push origin "${branch}:mr/test/${branch}"
    git cnb pull create -H "mr/test/${branch}" -B test
}

function mrp {
    $branch = git rev-parse --abbrev-ref HEAD
    git push origin "${branch}:mr/prerelease/${branch}"
    git cnb pull create -H "mr/prerelease/${branch}" -B prerelease
}

# 规避和 mrt.exe 的重名问题
Set-Alias mrt mrt2 -Scope Global

